={
  "embeds": [
    {
      "title": "📅 NOUVEAU RDV PLANIFIÉ",
      "color": 3066993,
      "fields": [
        { "name": "🏢 Entreprise", "value": "{{ $json.business_name || 'Non renseigné' }}", "inline": false },
        { "name": "📍 Adresse", "value": "{{ $json.address || 'Non renseignée' }}", "inline": true },
        { "name": "🏙️ Ville", "value": "{{ $json.city || 'Non renseignée' }}", "inline": true },
        { "name": "📞 Téléphone", "value": "{{ $json.phone || 'Non renseigné' }}", "inline": true },
        { "name": "🔧 Secteur", "value": "{{ $json.sector || 'Non renseigné' }}", "inline": true },
        { "name": "📆 Date du RDV", "value": "{{ $json.appointment_date }}", "inline": true },
        { "name": "🕐 Heure", "value": "{{ $json.appointment_time }}", "inline": true },
        { "name": "🗺️ Google Maps", "value": "{{ $json.google_maps_url ? '[Voir sur Maps](' + $json.google_maps_url + ')' : 'Non disponible' }}", "inline": false },
        { "name": "📝 Notes", "value": "{{ $json.notes || 'Aucune' }}", "inline": false },
        { "name": "👤 Qualifié par", "value": "{{ $json.agent_name || 'Non assigné' }}", "inline": false }
